function getPrimeFactors(x: number): number[] {
    if (x < 2) return [];
    const factors = new Set<number>();
    for (let i = 2; i * i <= x; i++) {
        while (x % i === 0) {
            factors.add(i);
            x = Math.floor(x / i);
        }
    }
    if (x > 1) {
        factors.add(x);
    }
    return Array.from(factors);
